                    new AnimeProduct { Name = "Póster Recompensa Sanji", AnimeSeries = "One Piece", ImageThumbnailUrl = "/Images/Póster Recompensa Sanji.jpg", Price = 8.00m, ShortDescription = "Only Alive version", LongDescription = "Réplica del infame cartel de se busca de Vinsmoke Sanji con el mítico Only Alive, la orden especial que lo distingue del resto de la tripulación del Sombrero de Paja. Este póster de alta resolución impreso en papel envejecido de 30x42 cm reproduce fielmente el diseño mostrado en el anime con la borrosa foto de Sanji. Los bordes desgastados y el efecto amarillento del tiempo están impresos para máximo realismo. Incluye tubo de cartón para envío sin daños y cinta de montaje. Perfecto para decorar habitaciones, estudios o locales. Una pieza humorística e icónica de One Piece.", InStock = true, IsProductOfTheWeek = false, Category = Categories["Coleccionables"] },
