                    new AnimeProduct { Name = "Máscara de Ken Kaneki", AnimeSeries = "Tokyo Ghoul", ImageThumbnailUrl = "/Images/Máscara de Ken Kaneki.jpg", Price = 30.00m, ShortDescription = "Cuero sintético ajustable", LongDescription = "Réplica oficial de la icónica máscara de ghoul de Ken Kaneki, creada por el fabricante de máscaras Uta para el protagonista de Tokyo Ghoul. Fabricada en cuero sintético premium de color negro con los detalles blancos del diseño de boca con dientes y los remaches metálicos perfectamente reproducidos. El sistema de sujeción ajustable con correas de cuero garantiza comodidad durante horas. Talla única que se adapta a diferentes tamaños de cabeza. Perfecta para cosplay de alta calidad o exhibición en vitrina. Incluye caja de presentación con diseño temático de Tokyo Ghoul. Una pieza oscura e impresionante para fans del anime.", InStock = true, IsProductOfTheWeek = false, Category = Categories["Coleccionables"] },

                    // MANGA
                    new AnimeProduct { Name = "One Piece Vol. 100", AnimeSeries = "One Piece", ImageThumbnailUrl = "/Images/One Piece Vol. 100.jpg", Price = 9.99m, ShortDescription = "Edición conmemorativa", LongDescription = "El volumen 100 de One Piece es un hito histórico en el mundo del manga, celebrando más de 25 años de la obra maestra de Eiichiro Oda. Esta edición conmemorativa especial incluye portada holográfica con todos los personajes principales de la saga, páginas a color exclusivas de momentos icónicos y comentarios del propio Oda sobre su viaje creativo. El volumen narra los eventos cruciales de Wano con la batalla épica en la cima de Onigashima. Papel de alta calidad con impresión HD que resalta los detalles del arte de Oda. Incluye marcapáginas coleccionable y póster desplegable. El tomo más especial de la colección.", InStock = true, IsProductOfTheWeek = true, Category = Categories["Manga"] },
                    new AnimeProduct { Name = "Naruto Gold Vol. 1", AnimeSeries = "Naruto", ImageThumbnailUrl = "/Images/Naruto Gold Vol. 1.jpg", Price = 12.00m, ShortDescription = "Portada metalizada", LongDescription = "La edición Gold de Naruto Vol. 1 es la versión definitiva para coleccionistas del inicio de la aventura del ninja más famoso de Konoha. La portada metalizada con acabado holográfico dorado y plateado brilla espectacularmente bajo cualquier luz. Este primer volumen narra el origen de Naruto Uzumaki, el niño rechazado que sueña con convertirse en Hokage. Edición revisada con traducción mejorada y efectos de sonido en japonés transliterado. Papel couché premium que realza el arte original de Masashi Kishimoto. Incluye galería de arte exclusiva de las primeras páginas del manga. El mejor punto de entrada a la colección de Naruto.", InStock = true, IsProductOfTheWeek = false, Category = Categories["Manga"] },
                    new AnimeProduct { Name = "Berserk Deluxe Vol. 1", AnimeSeries = "Berserk", ImageThumbnailUrl = "/Images/Berserk Deluxe Vol. 1.jpg", Price = 49.99m, ShortDescription = "Tapa dura, formato grande", LongDescription = "La edición Deluxe de Berserk en tapa dura y formato extra grande es la manera definitiva de experimentar la obra maestra de Kentaro Miura. Este primer volumen recopila los tomos 1, 2 y 3 del manga original en un impresionante libro de 672 páginas con papel de alta calidad que reproduce fielmente el extraordinario nivel artístico de Miura. El formato 18x25 cm permite apreciar cada detalle de las composiciones épicas del mangaka. La cubierta rígida con acabado mate y relieve presenta a Guts el Espadachín Negro en todo su esplendor oscuro. Incluye página de introducción por el editor. Un tributo digno al legado de Miura.", InStock = true, IsProductOfTheWeek = false, Category = Categories["Manga"] },
                    new AnimeProduct { Name = "Chainsaw Man Vol. 1", AnimeSeries = "Chainsaw Man", ImageThumbnailUrl = "/Images/Chainsaw Man Vol. 1.jpg", Price = 9.99m, ShortDescription = "El inicio de Denji", LongDescription = "El primer volumen de Chainsaw Man presenta a Denji, un joven cazador de demonios que sobrevive miserablemente con su perro-demonio Pochita hasta que una traición lo lleva a fusionarse con él convirtiéndose en el hombre-motosierra. La obra de Tatsuki Fujimoto arrasó con todos los premios de manga en 2020 gracias a su narrativa impredecible y su arte dinámico y expresivo. Este primer volumen establece el tono oscuro, humorístico y completamente original de la serie. Papel de alta calidad con impresión nítida que captura cada línea del arte de Fujimoto. La historia más fresca y sorprendente del manga moderno japonés.", InStock = true, IsProductOfTheWeek = false, Category = Categories["Manga"] },
                    new AnimeProduct { Name = "Spy x Family Vol. 1", AnimeSeries = "Spy x Family", ImageThumbnailUrl = "/Images/Spy x Family Vol. 1.jpg", Price = 9.99m, ShortDescription = "Misión: Formar una familia", LongDescription = "El primer volumen de Spy x Family presenta la premisa más original del manga reciente: un espía de élite que debe formar una familia falsa para completar una misión, adoptando sin saberlo a una niña telépata y casándose con una asesina secreta. La obra de Tatsuya Endo combina acción, comedia y momentos emotivos con un equilibrio perfecto que enamoró a millones de lectores mundialmente. Anya, la pequeña protagonista, se convirtió en uno de los personajes más populares del anime moderno. Este primer volumen establece los cimientos de una de las familias más disfuncionales y adorables del manga japonés contemporáneo.", InStock = true, IsProductOfTheWeek = false, Category = Categories["Manga"] },
                    new AnimeProduct { Name = "Jujutsu Kaisen 0", AnimeSeries = "Jujutsu Kaisen", ImageThumbnailUrl = "/Images/Jujutsu Kaisen 0.png", Price = 9.99m, ShortDescription = "La precuela de Yuta Okkotsu", LongDescription = "Jujutsu Kaisen 0 es la precuela esencial que narra la historia de Yuta Okkotsu, el estudiante de primer año que porta una de las maldiciones más poderosas de la historia: el espíritu de su amiga de infancia Rika. Esta historia independiente de Gege Akutami fue la semilla de todo el universo de Jujutsu Kaisen y es fundamental para entender los eventos de la serie principal. La adaptación cinematográfica de esta historia fue un fenómeno mundial recaudando más de 100 millones de dólares. El arte más refinado de Akutami con acción de alto voltaje y momentos emotivos devastadores. Imprescindible para fans de la serie.", InStock = true, IsProductOfTheWeek = false, Category = Categories["Manga"] },
                    new AnimeProduct { Name = "JoJo's Bizarre Adventure Part 1", AnimeSeries = "JoJo's", ImageThumbnailUrl = "/Images/JoJo's Bizarre Adventure Part 1.jpg", Price = 19.99m, ShortDescription = "Phantom Blood Vol 1", LongDescription = "El inicio de la saga más extravagante y única del manga japonés: JoJo's Bizarre Adventure Parte 1 Phantom Blood. Hirohiko Araki presenta a Jonathan Joestar, el primer JoJo, en su lucha contra Dio Brando en la Inglaterra victoriana del siglo XIX. Esta primera parte establece el universo Joestar con el poder del Hamon y los vampiros creados por la Máscara de Piedra. La edición en color premium reproduce la coloración original de Araki en todas sus páginas. La influencia de la moda italiana y el arte renacentista en el estilo de Araki es visible desde estas primeras páginas. El inicio obligatorio de una de las mejores sagas del manga mundial.", InStock = true, IsProductOfTheWeek = false, Category = Categories["Manga"] },
                    new AnimeProduct { Name = "Akira (Edición Integral)", AnimeSeries = "Akira", ImageThumbnailUrl = "/Images/Akira (Edición Integral).jpg", Price = 35.00m, ShortDescription = "Clásico cyberpunk", LongDescription = "La edición integral de Akira reúne en un solo volumen monumental la obra cumbre del manga cyberpunk de Katsuhiro Otomo. Publicada originalmente entre 1982 y 1990, esta historia ambientada en Neo-Tokyo post-apocalíptica definió el género cyberpunk en Japón y dio origen a la película animada que revolucionó la animación mundial. El arte de Otomo es de una precisión y detalle arquitectónico sin precedentes en el manga. Esta edición de lujo en tapa dura de 360 páginas incluye páginas a color originales y comentarios del autor. Papel de alta gramaje que preserva los negros profundos del arte de Otomo. Una obra de arte literaria e histórica.", InStock = true, IsProductOfTheWeek = false, Category = Categories["Manga"] },
                    new AnimeProduct { Name = "Dragon Ball Color Vol. 1", AnimeSeries = "Dragon Ball", ImageThumbnailUrl = "/Images/Dragon Ball Color Vol. 1.jpg", Price = 14.00m, ShortDescription = "Saga de los Saiyans a color", LongDescription = "Dragon Ball Color Vol. 1 presenta la icónica Saga de los Saiyans completamente coloreada bajo la supervisión de Shueisha, ofreciendo una experiencia de lectura completamente nueva del manga clásico de Akira Toriyama. El color añade una dimensión dramática completamente nueva a las batallas épicas entre Goku, Vegeta, Piccolo y los guerreros Saiyan. El volumen incluye la llegada de Raditz, el entrenamiento de Gohan con Piccolo y los primeros pasos hacia la batalla de Nappa y Vegeta. La coloración digital respeta el estilo original de Toriyama mientras añade profundidad y emoción visual. Papel couché brillante para máximo impacto visual en cada página.", InStock = true, IsProductOfTheWeek = false, Category = Categories["Manga"] },
                    new AnimeProduct { Name = "Uzumaki (Junji Ito)", AnimeSeries = "Terror", ImageThumbnailUrl = "/Images/Uzumaki (Junji Ito).jpg", Price = 25.00m, ShortDescription = "Obra maestra del horror", LongDescription = "Uzumaki de Junji Ito es considerada unánimemente la obra de terror más perturbadora y artísticamente sublime del manga japonés. Esta historia narra la maldición de una ciudad japonesa obsesionada con las espirales de una manera que escala gradualmente desde lo inquietante hasta lo absolutamente aterrador. El arte de Ito alcanza cimas de detalle hipnótico que hacen que cada página sea imposible de dejar de observar a pesar del horror que transmiten. Edición integral en tapa dura que recopila los tres volúmenes originales. Papel negro de alta calidad que realza los contrastes extremos del arte de Ito. No recomendada para personas con espiral-fobia.", InStock = true, IsProductOfTheWeek = false, Category = Categories["Manga"] },

